# Example: Competency verification scoring model
competency_levels = {
    'awareness': {'min_score': 70, 'badge': 'genai-aware', 'renewal_months': 12},
    'practitioner': {'min_score': 80, 'badge': 'genai-practitioner', 'renewal_months': 6},
    'champion': {'min_score': 90, 'badge': 'genai-champion', 'renewal_months': 6},
    'expert': {'min_score': 95, 'badge': 'genai-expert', 'renewal_months': 12}
}

def assign_badge(role: str, assessment_score: float, practical_score: float) -> dict:
    weighted = (assessment_score * 0.4) + (practical_score * 0.6)
    for level, config in sorted(competency_levels.items(),
                                key=lambda x: -x[1]['min_score']):
        if weighted >= config['min_score']:
            return {
                'level': level,
                'badge': config['badge'],
                'score': weighted,
                'renewal_due_months': config['renewal_months']
            }
    return {'level': 'not_certified', 'score': weighted}
